const ROLE_LABELS = {
  CC: "Chapter Chair", LO: "Learning Officer", ALO: "Assistant Learning Officer",
  FO: "Forum Officer", MO: "Membership Officer", MEO: "Member Engagement Officer",
};

function ChapterTooltipCell({ role, rowKey, val, denom, color, allChapters }) {
  const [show, setShow] = useState(false);

  const getChaptersForCell = () => {
    if (rowKey === "applicable" || rowKey === "missed") return [];
    return allChapters.filter(ch => {
      const blank =
        (role === "MEO" && ch.type !== "YPO Gold") ||
        (role === "MO"  && ch.type === "YPO Gold");
      if (blank) return false;
      const v = ch[role];
      if (rowKey === "trained")      return v === "trained";
      if (rowKey === "untrained")    return v === "untrained";
      if (rowKey === "unregistered") return v === "unregistered";
      return false;
    }).map(ch => ch.name.replace("YPO ", ""));
  };

  const chapterList = getChaptersForCell();
  const hasTooltip = chapterList.length > 0;

  return (
    <div
      style={{
        position: "relative", padding: "18px 12px", textAlign: "center",
        borderLeft: "1px solid #e8edf5",
        display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 4,
        cursor: hasTooltip ? "default" : "default",
      }}
      onMouseEnter={() => hasTooltip && setShow(true)}
      onMouseLeave={() => setShow(false)}
    >
      <span style={{
        fontSize: 26, fontWeight: 800, color: val > 0 ? color : "#d0d8e8", lineHeight: 1,
        borderBottom: hasTooltip ? `2px dotted ${color}` : "none",
      }}>
        {val}
      </span>
      <span style={{ fontSize: 10, color: "#9aa0b4", fontWeight: 500 }}>/ {denom}</span>
      {val > 0 && rowKey !== "applicable" && (
        <div style={{ width: 36, height: 3, borderRadius: 2, background: "#e8edf5", marginTop: 2 }}>
          <div style={{ height: 3, borderRadius: 2, background: color, width: `${Math.round(val / denom * 100)}%` }} />
        </div>
      )}
      {show && (
        <div style={{
          position: "absolute", top: "calc(100% + 4px)", left: "50%", transform: "translateX(-50%)",
          background: "#1a2540", borderRadius: 8, padding: "10px 14px",
          boxShadow: "0 8px 32px rgba(0,0,0,0.25)", zIndex: 999,
          minWidth: 200, maxWidth: 280, textAlign: "left",
          border: "1px solid rgba(255,255,255,0.1)", pointerEvents: "none",
        }}>
          <div style={{ fontSize: 10, fontWeight: 700, color: "rgba(255,255,255,0.4)", letterSpacing: "0.08em", textTransform: "uppercase", marginBottom: 8 }}>
            {chapterList.length} chapter{chapterList.length !== 1 ? "s" : ""}
          </div>
          {chapterList.map((name, i) => (
            <div key={i} style={{
              fontSize: 11, color: "#fff", fontWeight: 500, padding: "4px 0",
              borderBottom: i < chapterList.length - 1 ? "1px solid rgba(255,255,255,0.07)" : "none",
            }}>{name}</div>
          ))}
        </div>
      )}
    </div>
  );
}

function MissedCell({ role, val, denom, color, expanded, onToggle }) {
  return (
    <div
      onClick={() => val > 0 && onToggle()}
      style={{
        padding: "18px 12px", textAlign: "center", borderLeft: "1px solid #e8edf5",
        display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 4,
        cursor: val > 0 ? "pointer" : "default",
        background: expanded ? "#fff0f0" : "transparent",
      }}
    >
      <span style={{ fontSize: 26, fontWeight: 800, color: val > 0 ? color : "#d0d8e8", lineHeight: 1 }}>
        {val}
      </span>
      <span style={{ fontSize: 10, color: "#9aa0b4", fontWeight: 500 }}>/ {denom}</span>
      {val > 0 && (
        <div style={{ width: 36, height: 3, borderRadius: 2, background: "#e8edf5", marginTop: 2 }}>
          <div style={{ height: 3, borderRadius: 2, background: color, width: `${Math.round(val / denom * 100)}%` }} />
        </div>
      )}
      {val > 0 && (
        <span style={{ fontSize: 9, color: color, fontWeight: 600, marginTop: 2 }}>
          {expanded ? "▲ hide" : "▼ show"}
        </span>
      )}
    </div>
  );
}

function RolesView({ allChapters }) {
  const total = allChapters.length;
  const [expandedRow, setExpandedRow] = useState(null); // { key: 'missed'|'unregistered', role }

  const getStats = (role) => {
    let trained = 0, untrained = 0, unregistered = 0;
    allChapters.forEach(ch => {
      const blank =
        (role === "MEO" && ch.type !== "YPO Gold") ||
        (role === "MO"  && ch.type === "YPO Gold");
      if (blank) return;
      const val = ch[role];
      if (val === "trained")       trained++;
      else if (val === "untrained") untrained++;
      else                          unregistered++;
    });
    const missed   = roleData[role]?.missed.length || 0;
    const applicable = trained + untrained + unregistered;
    return { trained, untrained, unregistered, missed, applicable };
  };

  const roleOrder = ["CC", "LO", "ALO", "FO", "MO", "MEO"];
  const missedColor = "#c0392b";

  const rows = [
    { key: "applicable",   label: "Applicable Chapters",    color: "#8892b0", icon: "#"  },
    { key: "trained",      label: "Registered & Trained",   color: "#1a7a3a", icon: "✓" },
    { key: "untrained",    label: "Registered & Untrained", color: "#d4881a", icon: "◑" },
    { key: "missed",       label: "Missed Training",        color: missedColor, icon: "⚠" },
    { key: "unregistered", label: "Unregistered",           color: "#e05566", icon: "✗" },
  ];

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
      {/* Disclaimer */}
      <div style={{
        display: "flex", alignItems: "flex-start", gap: 10,
        background: "#fffbeb", border: "1px solid #f5d76e",
        borderRadius: 8, padding: "12px 16px", marginBottom: 12,
      }}>
        <span style={{ fontSize: 16, flexShrink: 0, marginTop: 1 }}>⚠️</span>
        <p style={{ fontSize: 11.5, color: "#7d5a00", fontWeight: 500, lineHeight: 1.6, margin: 0 }}>
          <strong>Please note:</strong> The GLC team takes approx. 1 week to manually update officer attendance for virtual training. If you are checking too soon after the training took place, you might see false negatives under "Missed Training". Please verify before reaching out to officers to re-register.
        </p>
      </div>
      {/* Header */}
      <div style={{
        display: "grid", gridTemplateColumns: "180px repeat(6, 1fr)",
        background: YPO_NAVY, borderRadius: "10px 10px 0 0",
      }}>
        <div style={{ padding: "14px 20px", fontSize: 10, fontWeight: 700, color: "rgba(255,255,255,0.5)", letterSpacing: "0.1em", textTransform: "uppercase" }}>Metric</div>
        {roleOrder.map(r => (
          <div key={r} style={{ padding: "14px 12px", textAlign: "center", borderLeft: "1px solid rgba(255,255,255,0.1)" }}>
            <div style={{ fontSize: 14, fontWeight: 800, color: "#fff" }}>{r}</div>
            <div style={{ fontSize: 9, color: "rgba(255,255,255,0.4)", marginTop: 2 }}>{ROLE_LABELS[r]}</div>
          </div>
        ))}
      </div>

      {/* Data rows */}
      {rows.map((row, ri) => {
        const isLast = ri === rows.length - 1;
        return (
          <div key={row.key}>
            <div style={{
              display: "grid", gridTemplateColumns: "180px repeat(6, 1fr)",
              background: ri % 2 === 0 ? "#fff" : "#f8f9fd",
              borderBottom: "1px solid #e8edf5",
              borderRadius: isLast && expandedRow === null ? "0 0 10px 10px" : 0,
              boxShadow: isLast && expandedRow === null ? "0 1px 3px rgba(0,47,108,0.06),0 4px 16px rgba(0,47,108,0.08)" : "none",
            }}>
              {/* Row label */}
              <div style={{
                padding: "18px 20px", display: "flex", alignItems: "center", gap: 10,
                borderRight: "1px solid #e8edf5",
              }}>
                <span style={{
                  width: 22, height: 22, borderRadius: 5,
                  background: row.color + "18", color: row.color,
                  display: "flex", alignItems: "center", justifyContent: "center",
                  fontSize: 12, fontWeight: 800, flexShrink: 0,
                }}>{row.icon}</span>
                <span style={{ fontSize: 11, fontWeight: 600, color: "#4a5568" }}>{row.label}</span>
              </div>

              {/* Cells */}
              {roleOrder.map(r => {
                const stats = getStats(r);
                const val   = stats[row.key];
                const denom = row.key === "applicable" ? total : stats.applicable;

                if (row.key === "missed") {
                  return (
                    <MissedCell
                      key={r}
                      role={r}
                      val={val}
                      denom={denom}
                      color={row.color}
                      expanded={expandedRow?.key === 'missed' && expandedRow?.role === r}
                      onToggle={() => setExpandedRow(expandedRow?.key === 'missed' && expandedRow?.role === r ? null : { key: 'missed', role: r })}
                    />
                  );
                }

                if (row.key === "unregistered") {
                  return (
                    <MissedCell
                      key={r}
                      role={r}
                      val={val}
                      denom={denom}
                      color={row.color}
                      expanded={expandedRow?.key === 'unregistered' && expandedRow?.role === r}
                      onToggle={() => setExpandedRow(expandedRow?.key === 'unregistered' && expandedRow?.role === r ? null : { key: 'unregistered', role: r })}
                    />
                  );
                }

                return (
                  <ChapterTooltipCell
                    key={r}
                    role={r}
                    rowKey={row.key}
                    val={val}
                    denom={denom}
                    color={row.color}
                    allChapters={allChapters}
                  />
                );
              })}
            </div>

            {/* Missed expand panel — only under the missed row */}
            {row.key === "missed" && expandedRow?.key === "missed" && roleData[expandedRow.role]?.missed.length > 0 && (
              <div style={{
                background: "#fff",
                border: "1px solid #f5c6cb",
                borderTop: "none",
              }}>
                {/* Sub-header */}
                <div style={{
                  display: "grid", gridTemplateColumns: "180px repeat(6, 1fr)",
                  background: "#fce8ea", padding: "8px 0",
                  borderBottom: "1px solid #f5c6cb",
                }}>
                  <div style={{ padding: "0 20px", fontSize: 10, fontWeight: 700, color: missedColor, display: "flex", alignItems: "center", gap:6 }}>
                    ⚠ {expandedRow.role} — Missed Sessions
                  </div>
                  {roleOrder.map(r => (
                    <div key={r} style={{ borderLeft: "1px solid #f5c6cb" }} />
                  ))}
                </div>

                {/* Missed entries */}
                {roleData[expandedRow.role].missed.map((item, idx) => {

                  return (
                    <div key={idx} style={{
                      display: "grid", gridTemplateColumns: "180px repeat(6, 1fr)",
                      background: idx % 2 === 0 ? "#fff" : "#fff8f8",
                      borderBottom: idx < roleData[expandedRow.role].missed.length - 1 ? "1px solid #fce8ea" : "none",
                    }}>
                      <div style={{ padding: "10px 20px", borderRight: "1px solid #fce8ea",
                        fontSize: 11, fontWeight: 700, color: "#002F6C", display:"flex", alignItems:"center" }}>
                        {item.chapter.replace("YPO ", "")}
                      </div>
                      {roleOrder.map((r, ci) => (
                        <div key={r} style={{ padding: "10px 14px", borderLeft: "1px solid #fce8ea" }}>
                          {r === expandedRow.role && (
                            <div style={{ display:"flex", flexDirection:"column", gap:2 }}>
                              <span style={{ fontSize: 11, color: "#555", fontWeight:500 }}>{item.session}</span>
                              <span style={{ fontSize: 10, fontWeight: 700, color: missedColor }}>{item.date} · {item.location}</span>
                            </div>
                          )}
                        </div>
                      ))}
                    </div>
                  );
                })}
              </div>
            )}

            {/* Unregistered expand panel */}
            {row.key === "unregistered" && expandedRow?.key === "unregistered" && (() => {
              const role = expandedRow.role;
              const unregChapters = allChapters.filter(ch => {
                const blank =
                  (role === "MEO" && ch.type !== "YPO Gold") ||
                  (role === "MO"  && ch.type === "YPO Gold");
                return !blank && ch[role] === "unregistered";
              });
              if (unregChapters.length === 0) return null;
              const unreColor = "#e05566";
              return (
                <div style={{ background:"#fff", border:"1px solid #fbc8ce", borderTop:"none" }}>
                  <div style={{
                    display:"grid", gridTemplateColumns:"180px repeat(6, 1fr)",
                    background:"#fde8ea", padding:"8px 0", borderBottom:"1px solid #fbc8ce",
                  }}>
                    <div style={{ padding:"0 20px", fontSize:10, fontWeight:700, color:unreColor, display:"flex", alignItems:"center", gap:6 }}>
                      ✗ {role} — Unregistered
                    </div>
                    {["CC","LO","ALO","FO","MO","MEO"].map(r => (
                      <div key={r} style={{ borderLeft:"1px solid #fbc8ce" }} />
                    ))}
                  </div>
                  {unregChapters.map((ch, idx) => (
                    <div key={idx} style={{
                      display:"grid", gridTemplateColumns:"180px repeat(6, 1fr)",
                      background: idx % 2 === 0 ? "#fff" : "#fff5f5",
                      borderBottom: idx < unregChapters.length - 1 ? "1px solid #fde8ea" : "none",
                    }}>
                      <div style={{ padding:"10px 20px", borderRight:"1px solid #fde8ea",
                        fontSize:11, fontWeight:700, color:"#002F6C", display:"flex", alignItems:"center" }}>
                        {ch.name.replace("YPO ","")}
                      </div>
                      {["CC","LO","ALO","FO","MO","MEO"].map(r => (
                        <div key={r} style={{ padding:"10px 14px", borderLeft:"1px solid #fde8ea", display:"flex", alignItems:"center" }}>
                          {r === role && (
                            <span style={{ fontSize:11, color:unreColor, fontWeight:600 }}>No officer registered</span>
                          )}
                        </div>
                      ))}
                    </div>
                  ))}
                </div>
              );
            })()}
          </div>
        );
      })}

      {/* Close rounding on last row */}
      <div style={{ height: 0, boxShadow: "0 4px 16px rgba(0,47,108,0.08)", borderRadius: "0 0 10px 10px" }} />
    </div>
  );
}


export default function App() {
  const [tab, setTab] = useState("status");

  const coreRoles = ch => ch.type === "YPO Gold"
    ? ["CC","LO","ALO","FO","MEO"]
    : ["CC","LO","ALO","FO","MO"];

  const [sortDir, setSortDir] = useState("desc");
  const [chapterSearch, setChapterSearch] = useState("");
  const [selectedChapters, setSelectedChapters] = useState([]);
  const [dropdownOpen, setDropdownOpen] = useState(false);

  const chapterNames = chapters.map(c => c.name);

  const toggleChapter = (name) => {
    setSelectedChapters(prev =>
      prev.includes(name) ? prev.filter(n => n !== name) : [...prev, name]
    );
  };

  const clearFilter = () => { setSelectedChapters([]); setChapterSearch(""); };

  const filtered = [...chapters]
    .filter(ch => selectedChapters.length === 0 || selectedChapters.includes(ch.name))
    .sort((a, b) => {
      const sa = coreRoles(a).filter(r => a[r] === "trained").length;
      const sb = coreRoles(b).filter(r => b[r] === "trained").length;
      return sortDir === "desc" ? sb - sa : sa - sb;
    });

  const filteredOptions = chapterNames.filter(n =>
    n.toLowerCase().includes(chapterSearch.toLowerCase())
  );

  const trainedCount    = ch => coreRoles(ch).filter(r => ch[r] === "trained").length;
  const applicableCount = ch => coreRoles(ch).length;
  const allFullyTrained = filtered.filter(ch => trainedCount(ch) === applicableCount(ch)).length;

  const isNonCoreBlank    = (ch, r) => (r==="MEO" && ch.type!=="YPO Gold" && ch[r]==="unregistered") || (r==="MO" && ch.type==="YPO Gold" && ch[r]==="unregistered");
  const isLocNonCoreBlank = (ch, r) => {
    const d = (locationData[ch.name] || {})[r];
    return ((r==="MEO" && ch.type!=="YPO Gold") || (r==="MO" && ch.type==="YPO Gold")) && (!d || d.status==="unregistered");
  };

  const thBase = (last) => ({
    padding:"12px 6px", textAlign:"center", fontSize:11, fontWeight:800, color:"#fff",
    letterSpacing:"0.08em", minWidth:70,
    borderRight: last ? "none" : "1px solid rgba(255,255,255,0.1)",
  });

  return (
    <div onClick={(e) => { if (!e.target.closest('.chapter-filter')) setDropdownOpen(false); }} style={{ fontFamily:"'Neue Montreal','Plus Jakarta Sans','DM Sans',system-ui,sans-serif", background:"#f4f6fb", minHeight:"100vh" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;500;600;700;800&display=swap');
        * { box-sizing:border-box; margin:0; padding:0; }
        ::-webkit-scrollbar { width:4px; height:4px; }
        ::-webkit-scrollbar-track { background:#e2e6f0; }
        ::-webkit-scrollbar-thumb { background:#b0b8d4; border-radius:2px; }
        tbody tr { transition:background 0.12s ease; }
        tbody tr:hover td.ch-cell { background:#003a82 !important; }
        tbody tr:hover td.data-cell { background:#e8eef8 !important; }
      `}</style>

      {/* Header */}
      <div style={{ background:YPO_NAVY, padding:"0 32px", display:"flex", alignItems:"center", justifyContent:"space-between", minHeight:72 }}>
        <div style={{ display:"flex", alignItems:"baseline", gap:8 }}>
          <span style={{ fontSize:28, fontWeight:800, color:"#fff", letterSpacing:"-0.5px" }}>MENA</span>
          <span style={{ fontSize:28, fontWeight:700, color:"#fff", letterSpacing:"-0.3px" }}>GLC Registrations</span>
        </div>
        <div style={{ display:"flex", alignItems:"center", gap:16 }}>
          <div style={{ display:"flex", alignItems:"center", gap:10 }}>
            {/* Chapter filter dropdown */}
            <div className="chapter-filter" style={{ position:"relative" }}>
              <button onClick={() => setDropdownOpen(o => !o)} style={{
                background:"rgba(255,255,255,0.12)", border:"1px solid rgba(255,255,255,0.22)",
                borderRadius:5, color:"#fff", padding:"5px 14px", fontSize:11,
                fontWeight:600, cursor:"pointer", fontFamily:"inherit", letterSpacing:"0.04em",
                display:"flex", alignItems:"center", gap:8, minWidth:160,
              }}>
                <span style={{ flex:1, textAlign:"left" }}>
                  {selectedChapters.length === 0 ? "Filter by Chapter" : `${selectedChapters.length} selected`}
                </span>
                {selectedChapters.length > 0 && (
                  <span onClick={(e) => { e.stopPropagation(); clearFilter(); }} style={{
                    fontSize:13, opacity:0.7, lineHeight:1, cursor:"pointer",
                  }}>✕</span>
                )}
                <span style={{ fontSize:9, opacity:0.7 }}>{dropdownOpen ? "▲" : "▼"}</span>
              </button>
              {dropdownOpen && (
                <div style={{
                  position:"absolute", top:"calc(100% + 6px)", right:0,
                  background:"#fff", borderRadius:8, boxShadow:"0 8px 32px rgba(0,47,108,0.18)",
                  width:260, zIndex:100, overflow:"hidden",
                }}>
                  <div style={{ padding:"8px 10px", borderBottom:"1px solid #eee" }}>
                    <input
                      autoFocus
                      placeholder="Search chapters..."
                      value={chapterSearch}
                      onChange={e => setChapterSearch(e.target.value)}
                      style={{
                        width:"100%", border:"1px solid #dde2ef", borderRadius:5,
                        padding:"5px 10px", fontSize:11, fontFamily:"inherit", color:"#002F6C", outline:"none",
                      }}
                    />
                  </div>
                  <div style={{ maxHeight:280, overflowY:"auto", padding:"4px 0" }}>
                    {filteredOptions.map(name => (
                      <div key={name} onClick={() => toggleChapter(name)} style={{
                        padding:"7px 12px", fontSize:11, cursor:"pointer", display:"flex", alignItems:"center", gap:8,
                        background: selectedChapters.includes(name) ? "#eef2fb" : "transparent",
                        color:"#002F6C", fontWeight: selectedChapters.includes(name) ? 600 : 400,
                      }}
                        onMouseEnter={e => e.currentTarget.style.background = selectedChapters.includes(name) ? "#e0e8f7" : "#f5f7fc"}
                        onMouseLeave={e => e.currentTarget.style.background = selectedChapters.includes(name) ? "#eef2fb" : "transparent"}
                      >
                        <div style={{
                          width:14, height:14, borderRadius:3, flexShrink:0,
                          border: selectedChapters.includes(name) ? "none" : "1.5px solid #b0b8d4",
                          background: selectedChapters.includes(name) ? "#002F6C" : "transparent",
                          display:"flex", alignItems:"center", justifyContent:"center",
                        }}>
                          {selectedChapters.includes(name) && <span style={{ color:"#fff", fontSize:9, fontWeight:800 }}>✓</span>}
                        </div>
                        {name}
                      </div>
                    ))}
                    {filteredOptions.length === 0 && (
                      <div style={{ padding:"10px 12px", fontSize:11, color:"#9aa0b4" }}>No chapters found</div>
                    )}
                  </div>
                  {selectedChapters.length > 0 && (
                    <div style={{ borderTop:"1px solid #eee", padding:"6px 12px" }}>
                      <button onClick={clearFilter} style={{
                        background:"none", border:"none", color:"#b82030", fontSize:11,
                        fontWeight:600, cursor:"pointer", fontFamily:"inherit", padding:0,
                      }}>Clear selection</button>
                    </div>
                  )}
                </div>
              )}
            </div>

            {/* Score sort */}
            <button onClick={() => setSortDir(d => d==="asc"?"desc":"asc")} style={{
              background:"rgba(255,255,255,0.12)", border:"1px solid rgba(255,255,255,0.22)",
              borderRadius:5, color:"#fff", padding:"5px 14px", fontSize:11,
              fontWeight:600, cursor:"pointer", fontFamily:"inherit", letterSpacing:"0.05em",
              display:"flex", alignItems:"center", gap:6,
            }}>
              {sortDir==="desc" ? "▼" : "▲"} {sortDir==="desc" ? "High → Low" : "Low → High"}
            </button>
          </div>
          <div style={{ borderLeft:"1px solid rgba(255,255,255,0.18)", paddingLeft:20, display:"flex", alignItems:"center" }}>
            <img src={YPO_LOGO} style={{ height:80, objectFit:"contain", mixBlendMode:"screen" }} alt="YPO Middle East & North Africa Region" />
          </div>
        </div>
      </div>

      {/* Tab bar */}
      <div style={{ background:"#fff", borderBottom:"1px solid #dde2ef", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
        <div style={{ display:"flex" }}>
          {[["status","Training Status"],["location","Training Location"],["roles","By Role"]].map(([t,label]) => (
            <button key={t} onClick={() => setTab(t)} style={{
              background:"none", border:"none",
              borderBottom: tab===t ? `3px solid ${YPO_NAVY}` : "3px solid transparent",
              color: tab===t ? YPO_NAVY : "#8892b0",
              fontFamily:"inherit", padding:"11px 28px", fontSize:12,
              fontWeight: tab===t ? 700 : 500, cursor:"pointer",
              letterSpacing:"0.04em", textTransform:"uppercase", transition:"all 0.15s",
            }}>{label}</button>
          ))}
        </div>
        <div style={{ display:"flex", gap:24, padding:"0 32px" }}>
          <span style={{ fontSize:11, color:"#8892b0", fontWeight:500 }}>
            <span style={{ color:YPO_NAVY, fontWeight:700 }}>{filtered.length}</span> chapters
          </span>
          <span style={{ fontSize:11, color:"#8892b0", fontWeight:500 }}>
            <span style={{ color:YPO_GREEN, fontWeight:700 }}>{allFullyTrained}</span> fully trained
          </span>
          <span style={{ fontSize:11, color:"#8892b0", fontWeight:500 }}>Data as of 13/04/2026</span>
        </div>
      </div>

      {/* Table */}
      <div style={{ overflowX:"auto", padding:"24px 32px 32px" }}>
        {tab === "roles" ? <RolesView allChapters={chapters} /> : null}
        {tab !== "roles" && <table style={{ borderCollapse:"collapse", width:"100%", background:"#fff", borderRadius:10, overflow:"hidden", boxShadow:"0 1px 3px rgba(0,47,108,0.06),0 4px 16px rgba(0,47,108,0.08)" }}>
          <thead>
            <tr style={{ background:YPO_NAVY }}>
              <th style={{ textAlign:"left", padding:"12px 20px", fontSize:10, fontWeight:700, color:"rgba(255,255,255,0.55)", letterSpacing:"0.1em", textTransform:"uppercase", minWidth:240, borderRight:"1px solid rgba(255,255,255,0.1)" }}>Chapter</th>
              {roles.map(r => <th key={r} style={thBase(r==="MEO")}>{r}<sup style={{ fontSize:7, opacity:0.6 }}>*</sup></th>)}
              {tab==="status" && <th style={{ padding:"12px 16px", textAlign:"center", fontSize:9, fontWeight:700, color:YPO_GREEN, letterSpacing:"0.08em", textTransform:"uppercase", minWidth:110, borderLeft:"1px solid rgba(255,255,255,0.1)", lineHeight:1.35 }}>Core Officer<br/>Trained</th>}
            </tr>
          </thead>
          <tbody>
            {filtered.map((ch, i) => {
              const isGold = ch.type === "YPO Gold";
              const tc     = trainedCount(ch);
              const tot    = applicableCount(ch);
              const scoreColor = tc===5 ? "#1a7a3a" : tc===4 ? "#9a6800" : "#b82030";
              const scoreBg    = tc===5 ? "#e5f4ea" : tc===4 ? "#fef3dc" : "#fce8ea";
              const locRow = locationData[ch.name] || {};
              return (
                <tr key={ch.name} style={{ background:i%2===0?"#fff":"#f8f9fd", borderBottom:"1px solid #e8edf5" }}>
                  <td className="ch-cell" style={{ padding:"7px 20px", fontSize:11.5, color:"#fff", fontWeight:600, background:YPO_NAVY, borderRight:"1px solid rgba(255,255,255,0.1)", whiteSpace:"nowrap", transition:"background 0.12s ease" }}>
                    {isGold && <span style={{ fontSize:8, background:"rgba(220,170,0,0.22)", color:"#f5cc2a", border:"1px solid rgba(220,170,0,0.45)", borderRadius:3, padding:"1px 5px", marginRight:8, fontWeight:800, letterSpacing:"0.06em" }}>GOLD</span>}
                    {ch.name}
                  </td>
                  {roles.map(r => (
                    <td key={r} className="data-cell" style={{ padding:"5px 4px", textAlign:"center", borderRight:r!=="MEO"?"1px solid #e8edf5":"none", transition:"background 0.12s ease" }}>
                      {tab === "status"
                        ? <StatusCell status={ch[r]} blank={isNonCoreBlank(ch,r)} />
                        : <LocCell cell={locRow[r]} blank={isLocNonCoreBlank(ch,r)} />}
                    </td>
                  ))}
                  {tab==="status" && (
                    <td className="data-cell" style={{ padding:"5px 16px", textAlign:"center", borderLeft:"1px solid #e8edf5", transition:"background 0.12s ease" }}>
                      <span style={{ display:"inline-flex", alignItems:"baseline", gap:2, padding:"3px 10px", borderRadius:5, fontSize:13, fontWeight:800, background:scoreBg, color:scoreColor, letterSpacing:"-0.3px" }}>
                        {tc}<span style={{ fontSize:10, fontWeight:500, opacity:0.7 }}>/{tot}</span>
                      </span>
                    </td>
                  )}
                </tr>
              );
            })}
          </tbody>
        </table>}
      </div>

      {/* Legend */}
      {tab === "status" && (
        <div style={{ padding:"0 32px 28px", display:"flex", alignItems:"center", gap:24, flexWrap:"wrap" }}>
          {Object.entries(STATUS).map(([key, { bg, text, label, icon }]) => (
            <div key={key} style={{ display:"flex", alignItems:"center", gap:8 }}>
              <div style={{ width:22, height:16, borderRadius:3, background:bg, display:"flex", alignItems:"center", justifyContent:"center", fontSize:10, color:text, fontWeight:700 }}>{icon}</div>
              <span style={{ fontSize:11, color:"#5a6282", fontWeight:500 }}>{label}</span>
            </div>
          ))}
          <span style={{ marginLeft:"auto", fontSize:10, color:"#9aa0b4", fontStyle:"italic" }}>* CC, LO, ALO, FO, MO core for YPO | CC, LO, ALO, FO, MEO core for Gold</span>
        </div>
      )}

      {tab === "location" && (
        <div style={{ padding:"0 32px 28px", display:"flex", alignItems:"center", gap:16, flexWrap:"wrap" }}>
          {[
            ["SYD ✓","#1a7a3a","Sydney — Completed"],
            ["CHI →","#1565C0","Chicago — Upcoming (~2 weeks)"],
            ["VIR ✓","#1a7a3a","Virtual — Completed"],
            ["VIR →","#1565C0","Virtual — Upcoming"],
            ["VIR ⚠","#c0392b","Virtual — Missed (registered but still untrained)"],
            ["PREV ✓","#6b7280","Previously Trained (prior cycle)"],
            ["✗",    "#b82030","Unregistered"],
          ].map(([badge, bg, lbl]) => (
            <div key={lbl} style={{ display:"flex", alignItems:"center", gap:8 }}>
              <div style={{ minWidth:46, height:16, borderRadius:3, background:bg, display:"flex", alignItems:"center", justifyContent:"center", fontSize:9, color:"#fff", fontWeight:800, padding:"0 4px" }}>{badge}</div>
              <span style={{ fontSize:11, color:"#5a6282", fontWeight:500 }}>{lbl}</span>
            </div>
          ))}
          <span style={{ marginLeft:"auto", fontSize:10, color:"#9aa0b4", fontStyle:"italic" }}>Hover a cell to see session name</span>
        </div>
      )}
    </div>
  );
}
